	/**
	 * Builds the expected throwable message.
	 * @param array $actualSubset The actualSubset.
	 * @param array $expectedArray The expectedArray.
	 * @param bool $strict The strict flag to pass.
	 * @param string $message The message to pass.
	 * @return string The expected throwable message.
	 */
	private static function buildExpectedThrowableMessage( array $actualSubset, array $expectedArray, bool $strict, string $message ): string
	{
		$messagePrefix = Values::EMPTY_STRING === $message
			? Values::EMPTY_STRING
			: sprintf( '%1$s%2$s', $message, "\n" );
		$constraint    = new IsKeyedSubsetOfArrayConstraint( $expectedArray, $strict );

		return sprintf(
			'%1$sFailed asserting that %2$s%3$s.',
			$messagePrefix,
			new ConstraintExposingValueToTypeStringFragmentMethodAccessor()
				->valueToTypeStringFragment( $actualSubset ),
			$constraint->toString()
		);
	}
